import{_ as o,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Country-Level Reporting for Google Ads and TikTok","description":"","frontmatter":{"title":"Country-Level Reporting for Google Ads and TikTok","slug":"country-level-reporting"},"headers":[],"relativePath":"account-hub/country-level-reporting.md","filePath":"account-hub/country-level-reporting.md"}'),i={name:"account-hub/country-level-reporting.md"};function a(l,e,s,c,d,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>You can now report on your Google Ads and TikTok campaign performance by <strong>Country</strong>. In addition to <strong>Country</strong>-level reporting, we will now populate the <strong>Channel</strong> and <strong>Secondary Publisher</strong> dimensions with descriptive values to help you understand more about your Google Ads campaign performance.</p><h2 id="view-country-level-metrics" tabindex="-1">View Country-Level Metrics <a class="header-anchor" href="#view-country-level-metrics" aria-label="Permalink to &quot;View Country-Level Metrics&quot;">​</a></h2><p>Complete the following steps to view <strong>Country</strong>-level metrics for Google Ads and TikTok:</p><ol><li>In the Branch Dashboard, select <strong>Ads</strong> &gt; <strong>Analytics</strong> &gt; <strong>Activity</strong>.</li><li>In the <strong>Events</strong> section, enter “country” in the <strong>Compare by</strong> text field.</li><li>Select “Enter” or “Return” on your keyboard to add the dimension.</li></ol><p>You can now view or export your metrics like ROAS, Cost, Clicks, Impressions, attributed events, and more sorted by <strong>Country</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Note</p><p>The <strong>OS</strong> and <strong>Platform</strong> dimensions can’t be combined with <strong>Country</strong> in Google Ads or TikTok reports. We’ll provide more compatibility information in the near future.</p></div><h2 id="view-channel-and-secondary-publisher-metrics" tabindex="-1">View Channel and Secondary Publisher Metrics <a class="header-anchor" href="#view-channel-and-secondary-publisher-metrics" aria-label="Permalink to &quot;View Channel and Secondary Publisher Metrics&quot;">​</a></h2><p>Complete the following steps to view <strong>Channel</strong>- or <strong>Secondary Publisher</strong>-level metrics for Google Ads:</p><ol><li>In the Branch Dashboard, select <strong>Ads</strong> &gt; <strong>Analytics</strong> &gt; <strong>Activity</strong>.</li><li>In the <strong>Events</strong> section, enter “channel” and/or “secondary publisher” in the <strong>Compare by</strong> text field.</li><li>Select “Enter” or “Return” on your keyboard to add the dimension.</li></ol><p>You can now view or export your metrics like ROAS, Cost, Clicks, Impressions, attributed events, and more sorted by <strong>Channel</strong> or <strong>Secondary Publisher</strong>.</p><h3 id="expected-values" tabindex="-1">Expected Values <a class="header-anchor" href="#expected-values" aria-label="Permalink to &quot;Expected Values&quot;">​</a></h3><p>You can expect the following values to populate your <strong>Channel</strong> field:</p><ul><li>Display</li><li>GoogleTV</li><li>Cross-network</li><li>Search</li><li>Youtube</li><li>Unpopulated</li></ul><p>You can expect the the following values to populate your <strong>Secondary Publisher</strong> field:</p><ul><li>Display</li><li>GoogleTV</li><li>Cross-network</li><li>GoogleSearch</li><li>SearchPartners</li><li>YouTubeVideos</li><li>Unpopulated</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>We surface as much insight as possible based on the data we receive from Google. If we don’t receive values that allow us to report with confidence, the data will be marked “Unpopulated.” We will enhance these available values as more data becomes available.</p></div><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><p>Read our <a href="./paid-ads-analytics.html">Ads Analytics</a> page to learn more about the available dimensions and reporting options.</p>',19)])])}const h=o(i,[["render",a]]);export{g as __pageData,h as default};
